import re

class TrieNode:
    def __init__(self):
        self.children = {}
        self.is_end_of_word = False
        self.replacement_value = None

class Trie:
    def __init__(self):
        self.root = TrieNode()

    def insert(self, original_word, replacement_word):
        node = self.root
        for char in original_word:
            if char not in node.children:
                node.children[char] = TrieNode()
            node = node.children[char]
        node.is_end_of_word = True
        node.replacement_value = replacement_word

    def get_replacement(self, word):
        node = self.root
        for char in word:
            if char not in node.children:
                return None
            node = node.children[char]
        if node.is_end_of_word:
            return node.replacement_value
        return None

def replace_words(text, replacements_dict):
    trie = Trie()
    for original, replacement in replacements_dict.items():
        trie.insert(original.lower(), replacement)

    split_parts = re.split(r'(\b\w+\b)', text)
    processed_parts = []

    for part in split_parts:
        if not part:
            continue

        if re.match(r'^\w+$', part):
            original_case_word = part
            lower_case_word = part.lower()
            replacement = trie.get_replacement(lower_case_word)

            if replacement:
                processed_parts.append(replacement)
            else:
                processed_parts.append(original_case_word)
        else:
            processed_parts.append(part)

    return "".join(processed_parts)
